CREATE INDEX IF NOT EXISTS "idx_listening_log_user_listened" ON public."LISTENING_LOG" ("USER_ID", "LISTENED_AT" DESC);
CREATE INDEX IF NOT EXISTS "idx_listening_log_listened_at"   ON public."LISTENING_LOG" ("LISTENED_AT" DESC); -- 전역 피드용

ALTER PUBLICATION supabase_realtime ADD TABLE public."LISTENING_LOG";

ALTER TABLE public."LISTENING_LOG" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "listening_log_read_all"   ON public."LISTENING_LOG";
DROP POLICY IF EXISTS "listening_log_insert_own" ON public."LISTENING_LOG";
DROP POLICY IF EXISTS "listening_log_update_own" ON public."LISTENING_LOG";
DROP POLICY IF EXISTS "listening_log_delete_own" ON public."LISTENING_LOG";
CREATE POLICY "listening_log_read_all"   ON public."LISTENING_LOG" FOR SELECT USING (true);
CREATE POLICY "listening_log_insert_own" ON public."LISTENING_LOG" FOR INSERT TO authenticated
  WITH CHECK ((select auth.uid()) = "USER_ID");
CREATE POLICY "listening_log_update_own" ON public."LISTENING_LOG" FOR UPDATE TO authenticated
  USING ((select auth.uid()) = "USER_ID")
  WITH CHECK ((select auth.uid()) = "USER_ID");
CREATE POLICY "listening_log_delete_own" ON public."LISTENING_LOG" FOR DELETE TO authenticated
  USING ((select auth.uid()) = "USER_ID");

-- EVENT_LOG.EVENT_TYPE에 다이어리/랜덤픽 이벤트 추가 (NOT VALID: 기존 행에 영향 없음)
ALTER TABLE public."EVENT_LOG" DROP CONSTRAINT IF EXISTS "event_log_type_check";
ALTER TABLE public."EVENT_LOG" ADD CONSTRAINT "event_log_type_check"
  CHECK ("EVENT_TYPE" IN ('VISIT','SIGNUP','LOGIN','SEARCH','SCAN','ALBUM_ADD','WISH_ADD','SHARE','SPIN_LOG','RANDOM_PICK')) NOT VALID;

-- 2026-07-14: 스피닝 다이어리 미디어 첨부(이미지 또는 15초 내외 짧은 영상 1개).
-- 업로드는 /api/spin-log/upload 서버 라우트가 인증 검증 후 service role로
-- spin-log-media 버킷(공개 read, 25MB 제한, 이미지/영상 MIME 화이트리스트)에 저장한다.
ALTER TABLE public."LISTENING_LOG" ADD COLUMN IF NOT EXISTS "MEDIA_URL" text;
ALTER TABLE public."LISTENING_LOG" ADD COLUMN IF NOT EXISTS "MEDIA_TYPE" text CHECK ("MEDIA_TYPE" IN ('image','video'));

-- 2026-07-14: 기록별 공개/비공개 — 기본값 true(기존 동작 유지: 지금까지의
-- 모든 기록은 전체 공개였다). false로 바꾼 기록은 작성자 본인만 볼 수 있다.
ALTER TABLE public."LISTENING_LOG" ADD COLUMN IF NOT EXISTS "IS_PUBLIC" boolean NOT NULL DEFAULT true;

-- 공개 읽기 정책을 "IS_PUBLIC=true이거나 본인 글"로 좁힌다 — 비공개로 바꾼
-- 기록은 타인에게 더 이상 보이지 않지만, 작성자 본인의 /log 페이지(비공개
-- 포함 전체 조회)는 계속 정상 동작해야 하므로 auth.uid()=USER_ID는 항상 통과.
DROP POLICY IF EXISTS "listening_log_read_all" ON public."LISTENING_LOG";
CREATE POLICY "listening_log_read_all" ON public."LISTENING_LOG" FOR SELECT
  USING ("IS_PUBLIC" = true OR (select auth.uid()) = "USER_ID");

