-- ============================================================
-- 유저 팔로우 + 취향 매칭 (2026-07-14)
-- Run this section manually in the Supabase SQL Editor.
--
-- 컬렉션(USER_VINYL)과 프로필(PROFILES)이 이미 전체 공개이므로 팔로우
-- 관계 공개도 새로운 노출이 아니다. 쓰기는 본인(FOLLOWER_ID = auth.uid())만.
-- ============================================================

CREATE TABLE IF NOT EXISTS public."USER_FOLLOW" (
    "FOLLOW_ID"    bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FOLLOWER_ID"  uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "FOLLOWING_ID" uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "CREATED_AT"   timestamp with time zone DEFAULT now(),
    CONSTRAINT "user_follow_unique"  UNIQUE ("FOLLOWER_ID", "FOLLOWING_ID"),
    CONSTRAINT "user_follow_no_self" CHECK ("FOLLOWER_ID" <> "FOLLOWING_ID")
);

CREATE INDEX IF NOT EXISTS "idx_user_follow_follower"  ON public."USER_FOLLOW" ("FOLLOWER_ID");
CREATE INDEX IF NOT EXISTS "idx_user_follow_following" ON public."USER_FOLLOW" ("FOLLOWING_ID");

ALTER TABLE public."USER_FOLLOW" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "user_follow_read_all"   ON public."USER_FOLLOW";
DROP POLICY IF EXISTS "user_follow_insert_own" ON public."USER_FOLLOW";
DROP POLICY IF EXISTS "user_follow_delete_own" ON public."USER_FOLLOW";
CREATE POLICY "user_follow_read_all"   ON public."USER_FOLLOW" FOR SELECT USING (true);
CREATE POLICY "user_follow_insert_own" ON public."USER_FOLLOW" FOR INSERT TO authenticated
  WITH CHECK ((select auth.uid()) = "FOLLOWER_ID");
CREATE POLICY "user_follow_delete_own" ON public."USER_FOLLOW" FOR DELETE TO authenticated
  USING ((select auth.uid()) = "FOLLOWER_ID");

-- 취향 매칭: 내 OWNED 앨범과 겹치는 수가 많은 유저를 DB에서 집계한다.
-- 일치율 = 겹침 ÷ LEAST(내 수집 수, 상대 수집 수) — "상대가 내 컬렉션의
-- 부분집합이면 100%"가 되는 관대한 정의(추천 문구용). USER_VINYL이 public
-- read라 SECURITY INVOKER(기본)로도 anon/authenticated 모두 실행 가능.
CREATE OR REPLACE FUNCTION public.get_taste_matches(p_user_id uuid, p_limit int DEFAULT 10)
RETURNS TABLE (
  user_id uuid,
  display_name text,
  overlap_count bigint,
  their_count bigint,
  match_percent int
)
LANGUAGE sql
STABLE
SET search_path = public
AS $$
  WITH mine AS (
    SELECT "ALBUM_ID" FROM public."USER_VINYL"
    WHERE "USER_ID" = p_user_id AND "STATUS" = 'OWNED'
  ),
  others AS (
    SELECT uv."USER_ID" AS uid,
           count(*) FILTER (WHERE uv."ALBUM_ID" IN (SELECT "ALBUM_ID" FROM mine)) AS overlap,
           count(*) AS total
    FROM public."USER_VINYL" uv
    WHERE uv."STATUS" = 'OWNED' AND uv."USER_ID" <> p_user_id
    GROUP BY uv."USER_ID"
  )
  SELECT o.uid,
         p."DISPLAY_NAME",
         o.overlap,
         o.total,
         round(100.0 * o.overlap / GREATEST(LEAST((SELECT count(*) FROM mine), o.total), 1))::int
  FROM others o
  LEFT JOIN public."PROFILES" p ON p."USER_ID" = o.uid
  WHERE o.overlap > 0
  ORDER BY o.overlap DESC, o.total ASC
  LIMIT p_limit;
$$;

-- EVENT_LOG.EVENT_TYPE에 FOLLOW 추가 (NOT VALID: 기존 행에 영향 없음)
ALTER TABLE public."EVENT_LOG" DROP CONSTRAINT IF EXISTS "event_log_type_check";
ALTER TABLE public."EVENT_LOG" ADD CONSTRAINT "event_log_type_check"
  CHECK ("EVENT_TYPE" IN ('VISIT','SIGNUP','LOGIN','SEARCH','SCAN','ALBUM_ADD','WISH_ADD','SHARE','SPIN_LOG','RANDOM_PICK','FOLLOW')) NOT VALID;

-- ============================================================
-- 프로필 공개/비공개 (2026-07-14, 2차)
-- Run this section manually in the Supabase SQL Editor.
--
-- IS_PUBLIC=false인 유저의 컬렉션은 본인·관리자 외에는 RLS 레벨에서
-- 조회가 차단된다 → 실시간 피드(Realtime 포함)·공유 프로필·취향 매칭에서
-- 자동으로 빠진다. PROFILES 행이 없는 유저는 공개로 간주(opt-out 방식).
-- ============================================================

ALTER TABLE public."PROFILES" ADD COLUMN IF NOT EXISTS "IS_PUBLIC" boolean NOT NULL DEFAULT true;

-- 명시적으로 비공개한 경우만 비공개 취급 (PROFILES 행 없음 = 공개)
CREATE OR REPLACE FUNCTION public.is_profile_public(p_user uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SET search_path = public
AS $$
  SELECT NOT EXISTS (
    SELECT 1 FROM public."PROFILES"
    WHERE "USER_ID" = p_user AND "IS_PUBLIC" = false
  );
$$;

-- USER_VINYL 읽기: 공개 프로필 전체 공개(퍼블릭 대시보드/피드 유지),
-- 비공개 프로필은 본인 + 관리자(app_metadata.role)만.
DROP POLICY IF EXISTS "user_vinyl_read_all" ON public."USER_VINYL";
CREATE POLICY "user_vinyl_read_all" ON public."USER_VINYL" FOR SELECT
  USING (
    (select auth.uid()) = "USER_ID"
    OR public.is_profile_public("USER_ID")
    OR (select auth.jwt() -> 'app_metadata' ->> 'role') = 'admin'
  );

-- 취향 매칭에서도 비공개 유저 제외
CREATE OR REPLACE FUNCTION public.get_taste_matches(p_user_id uuid, p_limit int DEFAULT 10)
RETURNS TABLE (
  user_id uuid,
  display_name text,
  overlap_count bigint,
  their_count bigint,
  match_percent int
)
LANGUAGE sql
STABLE
SET search_path = public
AS $$
  WITH mine AS (
    SELECT "ALBUM_ID" FROM public."USER_VINYL"
    WHERE "USER_ID" = p_user_id AND "STATUS" = 'OWNED'
  ),
  others AS (
    SELECT uv."USER_ID" AS uid,
           count(*) FILTER (WHERE uv."ALBUM_ID" IN (SELECT "ALBUM_ID" FROM mine)) AS overlap,
           count(*) AS total
    FROM public."USER_VINYL" uv
    WHERE uv."STATUS" = 'OWNED'
      AND uv."USER_ID" <> p_user_id
      AND public.is_profile_public(uv."USER_ID")
    GROUP BY uv."USER_ID"
  )
  SELECT o.uid,
         p."DISPLAY_NAME",
         o.overlap,
         o.total,
         round(100.0 * o.overlap / GREATEST(LEAST((SELECT count(*) FROM mine), o.total), 1))::int
  FROM others o
  LEFT JOIN public."PROFILES" p ON p."USER_ID" = o.uid
  WHERE o.overlap > 0
  ORDER BY o.overlap DESC, o.total ASC
  LIMIT p_limit;
$$;

-- ============================================================
-- 팔로우 목록 프라이버시 (2026-07-14, 3차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 팔로워/팔로잉 "목록"은 공개 프로필만 제3자에게 보인다. 비공개 유저가
-- 낀 관계 행은 당사자(팔로워/팔로잉 어느 쪽이든)와 관리자만 조회 가능 —
-- 비공개 유저는 남의 공개 팔로우 목록에서도 자동으로 빠진다.
-- ============================================================

DROP POLICY IF EXISTS "user_follow_read_all" ON public."USER_FOLLOW";
CREATE POLICY "user_follow_read_all" ON public."USER_FOLLOW" FOR SELECT
  USING (
    (select auth.uid()) IN ("FOLLOWER_ID", "FOLLOWING_ID")
    OR (select auth.jwt() -> 'app_metadata' ->> 'role') = 'admin'
    OR (public.is_profile_public("FOLLOWER_ID") AND public.is_profile_public("FOLLOWING_ID"))
  );

-- ============================================================
-- 팔로우 요청 + 카운트/목록 RPC (2026-07-14, 4차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 스펙: 비공개 프로필이어도 팔로워/팔로잉 "숫자"는 모두에게 보이고,
-- "목록"은 본인(+관리자)만. 공개 프로필은 목록도 공개. 비공개 프로필은
-- 바로 팔로우가 아니라 "팔로우 요청 → 대상자 수락" 방식.
-- (3차 섹션의 USER_FOLLOW 읽기 정책도 함께 실행돼 있어야 한다)
-- ============================================================

CREATE TABLE IF NOT EXISTS public."FOLLOW_REQUEST" (
    "REQUEST_ID"   bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "REQUESTER_ID" uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "TARGET_ID"    uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "CREATED_AT"   timestamp with time zone DEFAULT now(),
    CONSTRAINT "follow_request_unique"  UNIQUE ("REQUESTER_ID", "TARGET_ID"),
    CONSTRAINT "follow_request_no_self" CHECK ("REQUESTER_ID" <> "TARGET_ID")
);

CREATE INDEX IF NOT EXISTS "idx_follow_request_target" ON public."FOLLOW_REQUEST" ("TARGET_ID");

ALTER TABLE public."FOLLOW_REQUEST" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "follow_request_select_own" ON public."FOLLOW_REQUEST";
DROP POLICY IF EXISTS "follow_request_insert_own" ON public."FOLLOW_REQUEST";
DROP POLICY IF EXISTS "follow_request_delete_own" ON public."FOLLOW_REQUEST";
-- 조회: 당사자(요청자·대상자)와 관리자만
CREATE POLICY "follow_request_select_own" ON public."FOLLOW_REQUEST" FOR SELECT TO authenticated
  USING (
    (select auth.uid()) IN ("REQUESTER_ID", "TARGET_ID")
    OR (select auth.jwt() -> 'app_metadata' ->> 'role') = 'admin'
  );
-- 생성: 본인 명의 요청만
CREATE POLICY "follow_request_insert_own" ON public."FOLLOW_REQUEST" FOR INSERT TO authenticated
  WITH CHECK ((select auth.uid()) = "REQUESTER_ID");
-- 삭제: 요청자(취소) 또는 대상자(거절)
CREATE POLICY "follow_request_delete_own" ON public."FOLLOW_REQUEST" FOR DELETE TO authenticated
  USING ((select auth.uid()) IN ("REQUESTER_ID", "TARGET_ID"));

-- 카운트: 비공개 프로필 포함 누구나 — 집계 숫자만 노출하므로 안전
-- (테이블 RLS는 우회하되 개별 행은 반환하지 않는다)
CREATE OR REPLACE FUNCTION public.get_follow_counts(p_user uuid)
RETURNS TABLE (followers bigint, following bigint)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    (SELECT count(*) FROM public."USER_FOLLOW" WHERE "FOLLOWING_ID" = p_user),
    (SELECT count(*) FROM public."USER_FOLLOW" WHERE "FOLLOWER_ID" = p_user);
$$;

-- 목록: 본인/관리자/공개 프로필만 — 접근 검사를 함수 안에서 수행.
-- 목록 소유자(p_user)의 공개 여부만 따지므로, 비공개 유저도 남의 공개
-- 목록 안에는 나타난다(닉네임만 노출).
CREATE OR REPLACE FUNCTION public.get_follow_list(p_user uuid, p_type text, p_limit int DEFAULT 100)
RETURNS TABLE (user_id uuid, display_name text, followed_at timestamp with time zone)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT CASE WHEN p_type = 'followers' THEN uf."FOLLOWER_ID" ELSE uf."FOLLOWING_ID" END,
         p."DISPLAY_NAME",
         uf."CREATED_AT"
  FROM public."USER_FOLLOW" uf
  LEFT JOIN public."PROFILES" p
    ON p."USER_ID" = CASE WHEN p_type = 'followers' THEN uf."FOLLOWER_ID" ELSE uf."FOLLOWING_ID" END
  WHERE (CASE WHEN p_type = 'followers' THEN uf."FOLLOWING_ID" ELSE uf."FOLLOWER_ID" END) = p_user
    AND (
      (select auth.uid()) = p_user
      OR (select auth.jwt() -> 'app_metadata' ->> 'role') = 'admin'
      OR public.is_profile_public(p_user)
    )
  ORDER BY uf."CREATED_AT" DESC
  LIMIT p_limit;
$$;

-- 요청 수락: 대상자 본인만. 수락 시 요청자 명의의 USER_FOLLOW 행을 만들어야
-- 하는데 INSERT 정책(FOLLOWER_ID = auth.uid())상 대상자가 직접 넣을 수 없어
-- SECURITY DEFINER RPC로 처리한다.
CREATE OR REPLACE FUNCTION public.accept_follow_request(p_requester uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_target uuid := auth.uid();
BEGIN
  IF v_target IS NULL THEN
    RAISE EXCEPTION '로그인이 필요합니다.' USING ERRCODE = 'P0001';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public."FOLLOW_REQUEST"
    WHERE "REQUESTER_ID" = p_requester AND "TARGET_ID" = v_target
  ) THEN
    RAISE EXCEPTION '해당 팔로우 요청이 없습니다.' USING ERRCODE = 'P0001';
  END IF;
  INSERT INTO public."USER_FOLLOW" ("FOLLOWER_ID", "FOLLOWING_ID")
  VALUES (p_requester, v_target)
  ON CONFLICT ("FOLLOWER_ID", "FOLLOWING_ID") DO NOTHING;
  DELETE FROM public."FOLLOW_REQUEST"
  WHERE "REQUESTER_ID" = p_requester AND "TARGET_ID" = v_target;
END;
$$;

-- ============================================================
-- 전원 기본 비공개 전환 (2026-07-14, 5차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 공개/비공개는 새로 생긴 개념이라 기존 유저가 "원치 않은 공개" 상태가
-- 되지 않도록 전원 비공개로 초기화하고, 이후 가입자도 기본 비공개(opt-in
-- 공개)로 한다. is_profile_public()도 "명시적으로 공개한 경우만 공개"로
-- 재정의 — PROFILES 행이 없는 계정(닉네임 미설정)도 자동으로 비공개다.
-- ============================================================

ALTER TABLE public."PROFILES" ALTER COLUMN "IS_PUBLIC" SET DEFAULT false;
UPDATE public."PROFILES" SET "IS_PUBLIC" = false;

CREATE OR REPLACE FUNCTION public.is_profile_public(p_user uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public."PROFILES"
    WHERE "USER_ID" = p_user AND "IS_PUBLIC" = true
  );
$$;

-- ============================================================
-- 팔로워 열람 허용 (2026-07-14, 6차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 비공개 프로필이어도 "수락된 팔로워"는 해당 유저의 콘텐츠(보관함,
-- 피드 노출, 팔로우 목록)를 볼 수 있다 — 인스타그램 비공개 계정 방식.
-- 열람 판정을 can_view_profile() 하나로 모은다:
--   본인 OR 공개 프로필 OR 관리자 OR 수락된 팔로워
-- ============================================================

CREATE OR REPLACE FUNCTION public.can_view_profile(p_owner uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SET search_path = public
AS $$
  SELECT (select auth.uid()) = p_owner
      OR public.is_profile_public(p_owner)
      OR (select auth.jwt() -> 'app_metadata' ->> 'role') = 'admin'
      OR EXISTS (
           SELECT 1 FROM public."USER_FOLLOW"
           WHERE "FOLLOWING_ID" = p_owner
             AND "FOLLOWER_ID" = (select auth.uid())
         );
$$;

-- USER_VINYL 읽기: 열람 판정을 can_view_profile()로 일원화
DROP POLICY IF EXISTS "user_vinyl_read_all" ON public."USER_VINYL";
CREATE POLICY "user_vinyl_read_all" ON public."USER_VINYL" FOR SELECT
  USING (public.can_view_profile("USER_ID"));

-- 팔로우 목록도 수락된 팔로워에게 공개
CREATE OR REPLACE FUNCTION public.get_follow_list(p_user uuid, p_type text, p_limit int DEFAULT 100)
RETURNS TABLE (user_id uuid, display_name text, followed_at timestamp with time zone)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT CASE WHEN p_type = 'followers' THEN uf."FOLLOWER_ID" ELSE uf."FOLLOWING_ID" END,
         p."DISPLAY_NAME",
         uf."CREATED_AT"
  FROM public."USER_FOLLOW" uf
  LEFT JOIN public."PROFILES" p
    ON p."USER_ID" = CASE WHEN p_type = 'followers' THEN uf."FOLLOWER_ID" ELSE uf."FOLLOWING_ID" END
  WHERE (CASE WHEN p_type = 'followers' THEN uf."FOLLOWING_ID" ELSE uf."FOLLOWER_ID" END) = p_user
    AND public.can_view_profile(p_user)
  ORDER BY uf."CREATED_AT" DESC
  LIMIT p_limit;
$$;

-- ============================================================
-- 스피닝 다이어리 프로필 프라이버시 연동 (2026-07-14, 7차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 공개(IS_PUBLIC=true) 재생 기록도 프로필 열람 권한이 있는 사람
-- (본인/공개 프로필/관리자/수락된 팔로워)에게만 보이도록 일원화.
-- 비공개 기록은 종전대로 본인만.
-- ============================================================

DROP POLICY IF EXISTS "listening_log_read_all" ON public."LISTENING_LOG";
CREATE POLICY "listening_log_read_all" ON public."LISTENING_LOG" FOR SELECT
  USING (
    ("IS_PUBLIC" = true AND public.can_view_profile("USER_ID"))
    OR (select auth.uid()) = "USER_ID"
  );

-- ============================================================
-- 스피닝 다이어리 소셜 — 좋아요/댓글(답글)/저장/신고 (2026-07-14, 8차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 모든 상호작용은 "그 기록을 볼 수 있는 사람"(LISTENING_LOG RLS 통과)만
-- 가능하다 — 정책의 EXISTS 서브쿼리가 LISTENING_LOG의 RLS를 그대로 타므로
-- 비공개 프로필/비공개 기록에는 좋아요·댓글 자체가 불가능하다.
-- ============================================================

-- 좋아요
CREATE TABLE IF NOT EXISTS public."SPIN_LOG_LIKE" (
    "LIKE_ID"    bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "LOG_ID"     bigint NOT NULL REFERENCES public."LISTENING_LOG"("LOG_ID") ON DELETE CASCADE,
    "USER_ID"    uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "CREATED_AT" timestamp with time zone DEFAULT now(),
    CONSTRAINT "spin_like_unique" UNIQUE ("LOG_ID", "USER_ID")
);
CREATE INDEX IF NOT EXISTS "idx_spin_like_log" ON public."SPIN_LOG_LIKE" ("LOG_ID");

ALTER TABLE public."SPIN_LOG_LIKE" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "spin_like_select" ON public."SPIN_LOG_LIKE";
DROP POLICY IF EXISTS "spin_like_insert" ON public."SPIN_LOG_LIKE";
DROP POLICY IF EXISTS "spin_like_delete" ON public."SPIN_LOG_LIKE";
CREATE POLICY "spin_like_select" ON public."SPIN_LOG_LIKE" FOR SELECT
  USING (EXISTS (SELECT 1 FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_LIKE"."LOG_ID"));
CREATE POLICY "spin_like_insert" ON public."SPIN_LOG_LIKE" FOR INSERT TO authenticated
  WITH CHECK (
    (select auth.uid()) = "USER_ID"
    AND EXISTS (SELECT 1 FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_LIKE"."LOG_ID")
  );
CREATE POLICY "spin_like_delete" ON public."SPIN_LOG_LIKE" FOR DELETE TO authenticated
  USING ((select auth.uid()) = "USER_ID");

-- 댓글 (PARENT_COMMENT_ID로 1단계 답글 스레딩)
CREATE TABLE IF NOT EXISTS public."SPIN_LOG_COMMENT" (
    "COMMENT_ID"        bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "LOG_ID"            bigint NOT NULL REFERENCES public."LISTENING_LOG"("LOG_ID") ON DELETE CASCADE,
    "USER_ID"           uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "PARENT_COMMENT_ID" bigint REFERENCES public."SPIN_LOG_COMMENT"("COMMENT_ID") ON DELETE CASCADE,
    "CONTENT"           text NOT NULL CHECK (char_length("CONTENT") BETWEEN 1 AND 500),
    "CREATED_AT"        timestamp with time zone DEFAULT now()
);
CREATE INDEX IF NOT EXISTS "idx_spin_comment_log" ON public."SPIN_LOG_COMMENT" ("LOG_ID", "CREATED_AT");

ALTER TABLE public."SPIN_LOG_COMMENT" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "spin_comment_select" ON public."SPIN_LOG_COMMENT";
DROP POLICY IF EXISTS "spin_comment_insert" ON public."SPIN_LOG_COMMENT";
DROP POLICY IF EXISTS "spin_comment_delete" ON public."SPIN_LOG_COMMENT";
CREATE POLICY "spin_comment_select" ON public."SPIN_LOG_COMMENT" FOR SELECT
  USING (EXISTS (SELECT 1 FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_COMMENT"."LOG_ID"));
CREATE POLICY "spin_comment_insert" ON public."SPIN_LOG_COMMENT" FOR INSERT TO authenticated
  WITH CHECK (
    (select auth.uid()) = "USER_ID"
    AND EXISTS (SELECT 1 FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_COMMENT"."LOG_ID")
  );
-- 삭제: 댓글 작성자 본인 또는 그 다이어리 기록의 주인(자기 게시물 관리)
CREATE POLICY "spin_comment_delete" ON public."SPIN_LOG_COMMENT" FOR DELETE TO authenticated
  USING (
    (select auth.uid()) = "USER_ID"
    OR (select auth.uid()) = (SELECT l."USER_ID" FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_COMMENT"."LOG_ID")
  );

-- 저장(북마크) — 저장 목록은 본인만 조회
CREATE TABLE IF NOT EXISTS public."SPIN_LOG_SAVE" (
    "SAVE_ID"    bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "LOG_ID"     bigint NOT NULL REFERENCES public."LISTENING_LOG"("LOG_ID") ON DELETE CASCADE,
    "USER_ID"    uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "CREATED_AT" timestamp with time zone DEFAULT now(),
    CONSTRAINT "spin_save_unique" UNIQUE ("LOG_ID", "USER_ID")
);
CREATE INDEX IF NOT EXISTS "idx_spin_save_user" ON public."SPIN_LOG_SAVE" ("USER_ID");

ALTER TABLE public."SPIN_LOG_SAVE" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "spin_save_select" ON public."SPIN_LOG_SAVE";
DROP POLICY IF EXISTS "spin_save_insert" ON public."SPIN_LOG_SAVE";
DROP POLICY IF EXISTS "spin_save_delete" ON public."SPIN_LOG_SAVE";
CREATE POLICY "spin_save_select" ON public."SPIN_LOG_SAVE" FOR SELECT TO authenticated
  USING ((select auth.uid()) = "USER_ID");
CREATE POLICY "spin_save_insert" ON public."SPIN_LOG_SAVE" FOR INSERT TO authenticated
  WITH CHECK (
    (select auth.uid()) = "USER_ID"
    AND EXISTS (SELECT 1 FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_SAVE"."LOG_ID")
  );
CREATE POLICY "spin_save_delete" ON public."SPIN_LOG_SAVE" FOR DELETE TO authenticated
  USING ((select auth.uid()) = "USER_ID");

-- 신고 — 접수는 로그인 유저 누구나(기록당 1회), 열람은 본인 신고분/관리자만
CREATE TABLE IF NOT EXISTS public."SPIN_LOG_REPORT" (
    "REPORT_ID"   bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "LOG_ID"      bigint NOT NULL REFERENCES public."LISTENING_LOG"("LOG_ID") ON DELETE CASCADE,
    "REPORTER_ID" uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
    "REASON"      text CHECK (char_length("REASON") <= 300),
    "CREATED_AT"  timestamp with time zone DEFAULT now(),
    CONSTRAINT "spin_report_unique" UNIQUE ("LOG_ID", "REPORTER_ID")
);

ALTER TABLE public."SPIN_LOG_REPORT" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "spin_report_select" ON public."SPIN_LOG_REPORT";
DROP POLICY IF EXISTS "spin_report_insert" ON public."SPIN_LOG_REPORT";
CREATE POLICY "spin_report_select" ON public."SPIN_LOG_REPORT" FOR SELECT TO authenticated
  USING (
    (select auth.uid()) = "REPORTER_ID"
    OR (select auth.jwt() -> 'app_metadata' ->> 'role') = 'admin'
  );
CREATE POLICY "spin_report_insert" ON public."SPIN_LOG_REPORT" FOR INSERT TO authenticated
  WITH CHECK (
    (select auth.uid()) = "REPORTER_ID"
    AND EXISTS (SELECT 1 FROM public."LISTENING_LOG" l WHERE l."LOG_ID" = "SPIN_LOG_REPORT"."LOG_ID")
  );

-- ============================================================
-- 알림함 (2026-07-14, 9차)
-- Run this section manually in the Supabase SQL Editor.
--
-- 좋아요/댓글/답글/팔로우 이벤트를 DB 트리거가 NOTIFICATION으로 적재한다
-- (클라이언트 협조 불필요 — 웹/모바일 어디서 발생해도 쌓임). 좋아요 취소나
-- 팔로우 요청 취소 시 해당 알림도 정리. 클라이언트 INSERT 정책 없음.
-- ============================================================

CREATE TABLE IF NOT EXISTS public."NOTIFICATION" (
    "NOTIFICATION_ID"  bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "USER_ID"          uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,   -- 수신자
    "ACTOR_ID"         uuid REFERENCES auth.users(id) ON DELETE CASCADE,            -- 행위자
    "TYPE"             text NOT NULL CHECK ("TYPE" IN (
        'SPIN_LIKE','SPIN_COMMENT','SPIN_REPLY',
        'VINYL_LIKE','VINYL_COMMENT','VINYL_REPLY',
        'FOLLOW_REQUEST','FOLLOW_ACCEPTED','NEW_FOLLOWER')),
    "LOG_ID"           bigint REFERENCES public."LISTENING_LOG"("LOG_ID") ON DELETE CASCADE,
    "USER_VINYL_ID"    bigint REFERENCES public."USER_VINYL"("USER_VINYL_ID") ON DELETE CASCADE,
    "SPIN_COMMENT_ID"  bigint REFERENCES public."SPIN_LOG_COMMENT"("COMMENT_ID") ON DELETE CASCADE,
    "VINYL_COMMENT_ID" bigint REFERENCES public."VINYL_COMMENT"("COMMENT_ID") ON DELETE CASCADE,
    "COMMENT_PREVIEW"  text,                                                        -- 댓글 앞 80자
    "READ_AT"          timestamp with time zone,
    "CREATED_AT"       timestamp with time zone DEFAULT now()
);
CREATE INDEX IF NOT EXISTS "idx_notification_user" ON public."NOTIFICATION" ("USER_ID", "CREATED_AT" DESC);

ALTER TABLE public."NOTIFICATION" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "notification_select_own" ON public."NOTIFICATION";
DROP POLICY IF EXISTS "notification_update_own" ON public."NOTIFICATION";
DROP POLICY IF EXISTS "notification_delete_own" ON public."NOTIFICATION";
CREATE POLICY "notification_select_own" ON public."NOTIFICATION" FOR SELECT TO authenticated
  USING ((select auth.uid()) = "USER_ID");
CREATE POLICY "notification_update_own" ON public."NOTIFICATION" FOR UPDATE TO authenticated
  USING ((select auth.uid()) = "USER_ID")
  WITH CHECK ((select auth.uid()) = "USER_ID");
CREATE POLICY "notification_delete_own" ON public."NOTIFICATION" FOR DELETE TO authenticated
  USING ((select auth.uid()) = "USER_ID");

-- 미읽음 배지 실시간 갱신용 (RLS가 수신자 본인에게만 이벤트 전달)
-- 이미 등록돼 있으면 무시 — 섹션 전체 재실행에 안전하도록
DO $$ BEGIN
  ALTER PUBLICATION supabase_realtime ADD TABLE public."NOTIFICATION";
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- ── 트리거들 (SECURITY DEFINER — NOTIFICATION에 클라이언트 INSERT 정책이 없으므로) ──

-- 다이어리 좋아요
CREATE OR REPLACE FUNCTION public.notify_spin_like() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_owner uuid;
BEGIN
  SELECT "USER_ID" INTO v_owner FROM public."LISTENING_LOG" WHERE "LOG_ID" = NEW."LOG_ID";
  IF v_owner IS NOT NULL AND v_owner <> NEW."USER_ID" THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE","LOG_ID")
    VALUES (v_owner, NEW."USER_ID", 'SPIN_LIKE', NEW."LOG_ID");
  END IF;
  RETURN NEW;
END; $$;
DROP TRIGGER IF EXISTS trg_notify_spin_like ON public."SPIN_LOG_LIKE";
CREATE TRIGGER trg_notify_spin_like AFTER INSERT ON public."SPIN_LOG_LIKE"
  FOR EACH ROW EXECUTE FUNCTION public.notify_spin_like();

-- 좋아요 취소 시 알림 정리
CREATE OR REPLACE FUNCTION public.unnotify_spin_like() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  DELETE FROM public."NOTIFICATION"
  WHERE "TYPE" = 'SPIN_LIKE' AND "LOG_ID" = OLD."LOG_ID" AND "ACTOR_ID" = OLD."USER_ID";
  RETURN OLD;
END; $$;
DROP TRIGGER IF EXISTS trg_unnotify_spin_like ON public."SPIN_LOG_LIKE";
CREATE TRIGGER trg_unnotify_spin_like AFTER DELETE ON public."SPIN_LOG_LIKE"
  FOR EACH ROW EXECUTE FUNCTION public.unnotify_spin_like();

-- 다이어리 댓글/답글
CREATE OR REPLACE FUNCTION public.notify_spin_comment() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_owner uuid; v_parent_author uuid;
BEGIN
  SELECT "USER_ID" INTO v_owner FROM public."LISTENING_LOG" WHERE "LOG_ID" = NEW."LOG_ID";
  IF NEW."PARENT_COMMENT_ID" IS NOT NULL THEN
    SELECT "USER_ID" INTO v_parent_author FROM public."SPIN_LOG_COMMENT" WHERE "COMMENT_ID" = NEW."PARENT_COMMENT_ID";
  END IF;
  -- 답글: 부모 댓글 작성자에게
  IF v_parent_author IS NOT NULL AND v_parent_author <> NEW."USER_ID" THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE","LOG_ID","SPIN_COMMENT_ID","COMMENT_PREVIEW")
    VALUES (v_parent_author, NEW."USER_ID", 'SPIN_REPLY', NEW."LOG_ID", NEW."COMMENT_ID", left(NEW."CONTENT", 80));
  END IF;
  -- 댓글: 기록 주인에게 (답글 수신자와 중복이면 생략)
  IF v_owner IS NOT NULL AND v_owner <> NEW."USER_ID"
     AND (v_parent_author IS NULL OR v_owner <> v_parent_author) THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE","LOG_ID","SPIN_COMMENT_ID","COMMENT_PREVIEW")
    VALUES (v_owner, NEW."USER_ID", 'SPIN_COMMENT', NEW."LOG_ID", NEW."COMMENT_ID", left(NEW."CONTENT", 80));
  END IF;
  RETURN NEW;
END; $$;
DROP TRIGGER IF EXISTS trg_notify_spin_comment ON public."SPIN_LOG_COMMENT";
CREATE TRIGGER trg_notify_spin_comment AFTER INSERT ON public."SPIN_LOG_COMMENT"
  FOR EACH ROW EXECUTE FUNCTION public.notify_spin_comment();

-- 수집 게시물(피드) 좋아요
CREATE OR REPLACE FUNCTION public.notify_vinyl_like() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_owner uuid;
BEGIN
  SELECT "USER_ID" INTO v_owner FROM public."USER_VINYL" WHERE "USER_VINYL_ID" = NEW."USER_VINYL_ID";
  IF v_owner IS NOT NULL AND v_owner <> NEW."USER_ID" THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE","USER_VINYL_ID")
    VALUES (v_owner, NEW."USER_ID", 'VINYL_LIKE', NEW."USER_VINYL_ID");
  END IF;
  RETURN NEW;
END; $$;
DROP TRIGGER IF EXISTS trg_notify_vinyl_like ON public."VINYL_LIKE";
CREATE TRIGGER trg_notify_vinyl_like AFTER INSERT ON public."VINYL_LIKE"
  FOR EACH ROW EXECUTE FUNCTION public.notify_vinyl_like();

CREATE OR REPLACE FUNCTION public.unnotify_vinyl_like() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  DELETE FROM public."NOTIFICATION"
  WHERE "TYPE" = 'VINYL_LIKE' AND "USER_VINYL_ID" = OLD."USER_VINYL_ID" AND "ACTOR_ID" = OLD."USER_ID";
  RETURN OLD;
END; $$;
DROP TRIGGER IF EXISTS trg_unnotify_vinyl_like ON public."VINYL_LIKE";
CREATE TRIGGER trg_unnotify_vinyl_like AFTER DELETE ON public."VINYL_LIKE"
  FOR EACH ROW EXECUTE FUNCTION public.unnotify_vinyl_like();

-- 수집 게시물 댓글/답글
CREATE OR REPLACE FUNCTION public.notify_vinyl_comment() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_owner uuid; v_parent_author uuid;
BEGIN
  SELECT "USER_ID" INTO v_owner FROM public."USER_VINYL" WHERE "USER_VINYL_ID" = NEW."USER_VINYL_ID";
  IF NEW."PARENT_COMMENT_ID" IS NOT NULL THEN
    SELECT "USER_ID" INTO v_parent_author FROM public."VINYL_COMMENT" WHERE "COMMENT_ID" = NEW."PARENT_COMMENT_ID";
  END IF;
  IF v_parent_author IS NOT NULL AND v_parent_author <> NEW."USER_ID" THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE","USER_VINYL_ID","VINYL_COMMENT_ID","COMMENT_PREVIEW")
    VALUES (v_parent_author, NEW."USER_ID", 'VINYL_REPLY', NEW."USER_VINYL_ID", NEW."COMMENT_ID", left(NEW."CONTENT", 80));
  END IF;
  IF v_owner IS NOT NULL AND v_owner <> NEW."USER_ID"
     AND (v_parent_author IS NULL OR v_owner <> v_parent_author) THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE","USER_VINYL_ID","VINYL_COMMENT_ID","COMMENT_PREVIEW")
    VALUES (v_owner, NEW."USER_ID", 'VINYL_COMMENT', NEW."USER_VINYL_ID", NEW."COMMENT_ID", left(NEW."CONTENT", 80));
  END IF;
  RETURN NEW;
END; $$;
DROP TRIGGER IF EXISTS trg_notify_vinyl_comment ON public."VINYL_COMMENT";
CREATE TRIGGER trg_notify_vinyl_comment AFTER INSERT ON public."VINYL_COMMENT"
  FOR EACH ROW EXECUTE FUNCTION public.notify_vinyl_comment();

-- 팔로우 요청 (취소 시 알림 정리 포함)
CREATE OR REPLACE FUNCTION public.notify_follow_request() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE")
  VALUES (NEW."TARGET_ID", NEW."REQUESTER_ID", 'FOLLOW_REQUEST');
  RETURN NEW;
END; $$;
DROP TRIGGER IF EXISTS trg_notify_follow_request ON public."FOLLOW_REQUEST";
CREATE TRIGGER trg_notify_follow_request AFTER INSERT ON public."FOLLOW_REQUEST"
  FOR EACH ROW EXECUTE FUNCTION public.notify_follow_request();

CREATE OR REPLACE FUNCTION public.unnotify_follow_request() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  DELETE FROM public."NOTIFICATION"
  WHERE "TYPE" = 'FOLLOW_REQUEST' AND "USER_ID" = OLD."TARGET_ID" AND "ACTOR_ID" = OLD."REQUESTER_ID";
  RETURN OLD;
END; $$;
DROP TRIGGER IF EXISTS trg_unnotify_follow_request ON public."FOLLOW_REQUEST";
CREATE TRIGGER trg_unnotify_follow_request AFTER DELETE ON public."FOLLOW_REQUEST"
  FOR EACH ROW EXECUTE FUNCTION public.unnotify_follow_request();

-- 팔로우 성립: 대상자가 수락한 경우(요청 플로우)면 요청자에게 "수락됨",
-- 요청자가 직접 팔로우한 경우(공개 프로필)면 대상자에게 "새 팔로워"
CREATE OR REPLACE FUNCTION public.notify_new_follow() RETURNS trigger
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF (select auth.uid()) = NEW."FOLLOWING_ID" THEN
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE")
    VALUES (NEW."FOLLOWER_ID", NEW."FOLLOWING_ID", 'FOLLOW_ACCEPTED');
  ELSE
    INSERT INTO public."NOTIFICATION" ("USER_ID","ACTOR_ID","TYPE")
    VALUES (NEW."FOLLOWING_ID", NEW."FOLLOWER_ID", 'NEW_FOLLOWER');
  END IF;
  RETURN NEW;
END; $$;
DROP TRIGGER IF EXISTS trg_notify_new_follow ON public."USER_FOLLOW";
CREATE TRIGGER trg_notify_new_follow AFTER INSERT ON public."USER_FOLLOW"
  FOR EACH ROW EXECUTE FUNCTION public.notify_new_follow();

-- ============================================================
-- SIGNUP_NUMBER upsert-burn fix (2026-07-14)
-- Run this whole section manually in the Supabase SQL Editor.
--
-- The 2026-07-12 migration drew nextval() in a BEFORE INSERT trigger.
-- But app writes to PROFILES are upserts (nickname save/change) — on an
-- existing row the INSERT branch still consumes nextval() before the
-- conflict falls through to the UPDATE path, so every nickname upsert
-- burned a number and new signups skipped ahead (live data 2026-07-14:
-- the 32nd–35th profiles got #36, #42, #43, #44).
-- ============================================================

-- 1. BEFORE trigger no longer touches the sequence. INSERT strips
--    whatever the client sent (tamper guard); UPDATE keeps the number
--    immutable once assigned. A NULL OLD value still passes through so
--    step 2's AFTER-INSERT grant (and step 3's renumber) can land.
CREATE OR REPLACE FUNCTION public.assign_signup_number()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    NEW."SIGNUP_NUMBER" := NULL;
  ELSIF OLD."SIGNUP_NUMBER" IS NOT NULL THEN
    -- Already assigned — immutable, ignore whatever the client sent.
    NEW."SIGNUP_NUMBER" := OLD."SIGNUP_NUMBER";
  END IF;
  RETURN NEW;
END;
$$;

-- 2. Numbers are granted AFTER INSERT instead — this trigger only fires
--    when a row is actually inserted, never on an upsert's conflict/
--    UPDATE path, so the sequence can no longer burn.
CREATE OR REPLACE FUNCTION public.grant_signup_number()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  UPDATE public."PROFILES"
     SET "SIGNUP_NUMBER" = nextval('public.profiles_signup_seq')
   WHERE "USER_ID" = NEW."USER_ID" AND "SIGNUP_NUMBER" IS NULL;
  RETURN NULL;
END;
$$;
DROP TRIGGER IF EXISTS trg_grant_signup_number ON public."PROFILES";
CREATE TRIGGER trg_grant_signup_number
  AFTER INSERT ON public."PROFILES"
  FOR EACH ROW EXECUTE FUNCTION public.grant_signup_number();

-- 3. Renumber every profile by real signup order (same statement as the
--    2026-07-12 migration's step 4 — safe to re-run). Fixes the four
--    inflated rows; everyone else keeps their current number.
ALTER TABLE public."PROFILES" DISABLE TRIGGER trg_assign_signup_number;
WITH ordered AS (
  SELECT p."USER_ID", row_number() OVER (ORDER BY u.created_at) AS rn
  FROM public."PROFILES" p
  JOIN auth.users u ON u.id = p."USER_ID"
)
UPDATE public."PROFILES" p
SET "SIGNUP_NUMBER" = ordered.rn
FROM ordered
WHERE p."USER_ID" = ordered."USER_ID";
ALTER TABLE public."PROFILES" ENABLE TRIGGER trg_assign_signup_number;

-- 4. Pull the sequence back so the next real signup continues the count.
SELECT setval('public.profiles_signup_seq', GREATEST((SELECT count(*) FROM public."PROFILES"), 1));
